body:
I have run in to a couple of odd cases related to parameters on interfaces where verilator should probably be reporting errors or linter warnings.  There may be more edge cases along these lines that I have not yet stumbled across.  First, it seems like there is a scoping problem where interfaces defined in one module can be accessed from a different module without any complaints from verilator, and this seems to apply to both signals and parameters.  The second is that it seems that parameters can be accessed from a parameter array.  Attempting to access a signal results in the error "Can't find definition of 'pa' in dotted signal:pa.sig" (well, sort of, I wonder if it should refer to "sig" instead of "pa").  

    interface test_if #(
        parameter PARAM = 0
    )
    ();
        logic sig;

        modport p (
            output sig
        );

    endinterface

    module test_mod(
        test_if.p p,
        test_if.p pa[2]
    );

    localparam t1p = p.PARAM; // OK
    wire t1s = p.sig; // OK

    localparam t1ap1 = pa.PARAM; // vivado doesn't like this
    //wire t1sp1 = pa.sig; // Can't find definition of 'pa' in dotted signal: 'pa.sig'
    localparam t1ap2 = pa[0].PARAM; // OK
    wire t1sp2 = pa[0].sig; // OK

    localparam t1ap3 = t1.PARAM; // what???
    wire t1sp3 = t1.sig; // what???

    localparam t1ap4 = t1a.PARAM; // what???
    //wire t1as4 = t1a.sig; // Can't find definition of 't1a' in dotted signal: 't1a.sig'
    localparam t1ap5 = t1a[0].PARAM; // what???
    wire t1as5 = t1a[0].sig; // what???

    endmodule

    module top();

    test_if t1();

    localparam t1p = t1.PARAM; // OK
    wire t1s = t1.sig; // OK

    test_if t1a[2]();

    localparam t1ap1 = t1a.PARAM; // vivado doesn't like this
    //wire t1as1 = t1a.sig; // Can't find definition of 't1a' in dotted signal: 't1a.sig'
    localparam t1ap2 = t1a[0].PARAM; // OK
    wire t1as2 = t1a[0].sig; // OK

    //localparam p = bogus.PARAM; // Can't find definition of scope/variable: 'bogus'
    //wire s = bogus.sig; // Can't find definition of scope/variable: 'bogus'

    test_mod
    inst (
        .p(t1),
        .pa(t1a)
    );

    endmodule
